SELECT [Reserv__Assign_ Link].[Reserv__Assign_ Type], [Reserv__Assign_ Link].[Sales Document No_] AS ordineNumero, [Reserv__Assign_ Link].[Sales Line No_] AS OrdineRiga, [Reserv__Assign_ Link].[Source Document No_], [Reserv__Assign_ Link].[Source Line No_], Val([Reserved_Assigned Quantity]) AS assortmentQty, [Reserv__Assign_ Link].Type, [Reserv__Assign_ Link].[Source Type], Val([Reserved_Assigned Quantity])*[assortmentquantity] AS pairsQty, "PREN-ACQ" AS statusRiga, [Reserv__Assign_ Link].[Selling Season Code] AS [Season Code], [Reserv__Assign_ Link].[Date Reservation], [Purchase Line].[Requested Receipt Date], [Purchase Line].[Promised Receipt Date], [Purchase Line].[Planned Receipt Date], [Purchase Line].[Expected Receipt Date], [Purchase Line].[Location Code] AS SourceLocation, [Sales Header].[Location Code] AS SalesLocation
FROM (([Reserv__Assign_ Link] LEFT JOIN AssortimentiQuantita ON ([Reserv__Assign_ Link].[Assortment Code] = AssortimentiQuantita.[Assortment Code]) AND ([Reserv__Assign_ Link].[Assortment Variable Group] = AssortimentiQuantita.[Variable Group])) LEFT JOIN [Sales Header] ON [Reserv__Assign_ Link].[Sales Document No_] = [Sales Header].No_) LEFT JOIN [Purchase Line] ON ([Reserv__Assign_ Link].[Source Line No_] = [Purchase Line].[Line No_]) AND ([Reserv__Assign_ Link].[Source Document No_] = [Purchase Line].[Document No_])
WHERE ((([Reserv__Assign_ Link].[Reserv__Assign_ Type])=1) AND ((Val([Reserved_Assigned Quantity]))<>0) AND (([Reserv__Assign_ Link].Type)=20) AND (([Reserv__Assign_ Link].[Source Type])=1) AND (([Reserv__Assign_ Link].[Selling Season Code])=[forms]![principale]![filtroStagioneprenotazioni]));

